using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// FIX #3 (ValidateScopes): Singleton consuming a scoped service throws at startup
// in .NET 9 dev mode. Change CacheService to scoped to match its dependency's lifetime.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// FIX #1 (SocketsHttpHandler): In .NET 9, HttpClientFactory uses SocketsHttpHandler
// by default. Casting to HttpClientHandler throws InvalidCastException.
// Use ConfigurePrimaryHttpMessageHandler to set handler properties directly.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// FIX #2 (Header redaction): .NET 9 redacts all header values in Trace-level
// HttpClientFactory logs by default. Allowlist non-sensitive headers you need to see.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(header =>
        header != "X-Request-Id"
        && header != "X-Correlation-Id"
        && header != "Cache-Control"
        && header != "Accept"
        && header != "Content-Type"));

// FIX #4 (Forwarded Headers): .NET 9 ignores X-Forwarded-* headers from proxies not
// in KnownProxies/KnownNetworks. Add your reverse proxy address(es) here.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("10.0.0.1")); // TODO: replace with actual proxy IP
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

